import{_ as e,o as a,c as n,a7 as o}from"./chunks/framework.C4ZIv4ii.js";const u=JSON.parse('{"title":"Falcon Builder Overview","description":"","frontmatter":{},"headers":[],"relativePath":"builder/overview.md","filePath":"builder/overview.md","lastUpdated":1781554731000}'),r={name:"builder/overview.md"};function s(d,t,i,l,c,p){return a(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="falcon-builder-overview" tabindex="-1">Falcon Builder Overview <a class="header-anchor" href="#falcon-builder-overview" aria-label="Permalink to &quot;Falcon Builder Overview&quot;">​</a></h1><p>Falcon Builder is the visual drag-and-drop page builder built into Falcon CMS. Build complex page layouts directly inside the admin dashboard — no code, no templates, no page refreshes.</p><p>It works for <strong>Pages</strong>, <strong>Posts</strong>, <strong>Custom Post Types</strong>, the <strong>Header</strong>, and the <strong>Footer</strong>.</p><hr><h2 id="how-to-open-the-builder" tabindex="-1">How to Open the Builder <a class="header-anchor" href="#how-to-open-the-builder" aria-label="Permalink to &quot;How to Open the Builder&quot;">​</a></h2><h3 id="for-pages-posts" tabindex="-1">For Pages &amp; Posts <a class="header-anchor" href="#for-pages-posts" aria-label="Permalink to &quot;For Pages &amp; Posts&quot;">​</a></h3><ol><li>Go to <strong>Admin → Pages</strong> (or Posts / any CPT)</li><li>Open or create a content item</li><li>Click <strong>Open Builder</strong> in the editor toolbar</li><li>The builder canvas opens in full-screen mode</li></ol><h3 id="for-header-footer" tabindex="-1">For Header &amp; Footer <a class="header-anchor" href="#for-header-footer" aria-label="Permalink to &quot;For Header &amp; Footer&quot;">​</a></h3><ol><li>Go to <strong>Admin → Appearance → Builder Sections</strong></li><li>Click <strong>Edit Header</strong> or <strong>Edit Footer</strong></li><li>The same builder opens, scoped to that section</li></ol><hr><h2 id="builder-interface" tabindex="-1">Builder Interface <a class="header-anchor" href="#builder-interface" aria-label="Permalink to &quot;Builder Interface&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  [← Back]  Page Title       [Desktop][Tablet][Mobile]  │  ← Top bar</span></span>
<span class="line"><span>│            [Save Draft]  [Publish]                      │</span></span>
<span class="line"><span>├──────────────┬──────────────────────────────────────────┤</span></span>
<span class="line"><span>│              │                                          │</span></span>
<span class="line"><span>│   Sidebar    │           Canvas                         │</span></span>
<span class="line"><span>│  (Settings)  │   ┌────────────────────────────────┐    │</span></span>
<span class="line"><span>│              │   │  Container                     │    │</span></span>
<span class="line"><span>│              │   │  ┌──────────┐  ┌──────────┐   │    │</span></span>
<span class="line"><span>│              │   │  │ Column 1 │  │ Column 2 │   │    │</span></span>
<span class="line"><span>│              │   │  │ [Element]│  │ [Element]│   │    │</span></span>
<span class="line"><span>│              │   │  └──────────┘  └──────────┘   │    │</span></span>
<span class="line"><span>│              │   └────────────────────────────────┘    │</span></span>
<span class="line"><span>│              │   [+ Add Container]                      │</span></span>
<span class="line"><span>└──────────────┴──────────────────────────────────────────┘</span></span></code></pre></div><ul><li><strong>Canvas</strong> — the live preview of your page. Drag, drop, and click to edit</li><li><strong>Sidebar</strong> — appears on the right when you select an element, showing its settings</li><li><strong>Top bar</strong> — device preview toggles, save, and publish</li></ul><hr><h2 id="building-a-page-—-step-by-step" tabindex="-1">Building a Page — Step by Step <a class="header-anchor" href="#building-a-page-—-step-by-step" aria-label="Permalink to &quot;Building a Page — Step by Step&quot;">​</a></h2><h3 id="step-1-add-a-container" tabindex="-1">Step 1: Add a Container <a class="header-anchor" href="#step-1-add-a-container" aria-label="Permalink to &quot;Step 1: Add a Container&quot;">​</a></h3><p>Click <strong>+ Add Container</strong> at the bottom of the canvas. A modal opens where you choose the column layout:</p><table tabindex="0"><thead><tr><th>Layout</th><th>Use case</th></tr></thead><tbody><tr><td><code>1 column</code></td><td>Full-width hero, banner</td></tr><tr><td><code>1/2 + 1/2</code></td><td>Two-column content</td></tr><tr><td><code>1/3 + 2/3</code></td><td>Sidebar + content</td></tr><tr><td><code>1/3 + 1/3 + 1/3</code></td><td>Three-column features</td></tr><tr><td><code>1/4 × 4</code></td><td>Four-column cards</td></tr></tbody></table><h3 id="step-2-add-elements-to-columns" tabindex="-1">Step 2: Add Elements to Columns <a class="header-anchor" href="#step-2-add-elements-to-columns" aria-label="Permalink to &quot;Step 2: Add Elements to Columns&quot;">​</a></h3><p>Click the <strong>+</strong> button inside any column. The element picker opens — choose an element type and it&#39;s added instantly.</p><h3 id="step-3-edit-the-element" tabindex="-1">Step 3: Edit the Element <a class="header-anchor" href="#step-3-edit-the-element" aria-label="Permalink to &quot;Step 3: Edit the Element&quot;">​</a></h3><p>Click any element on the canvas to select it. Its settings appear in the <strong>sidebar</strong> on the right. Every change reflects live on the canvas.</p><h3 id="step-4-reorder" tabindex="-1">Step 4: Reorder <a class="header-anchor" href="#step-4-reorder" aria-label="Permalink to &quot;Step 4: Reorder&quot;">​</a></h3><ul><li><strong>Drag elements</strong> up/down within a column, or move them between columns</li><li><strong>Drag containers</strong> using the handle on the container toolbar to reorder rows</li></ul><h3 id="step-5-save-publish" tabindex="-1">Step 5: Save &amp; Publish <a class="header-anchor" href="#step-5-save-publish" aria-label="Permalink to &quot;Step 5: Save &amp; Publish&quot;">​</a></h3><ul><li><strong>Autosave</strong> runs every 30 seconds in the background</li><li><strong>Save Draft</strong> — saves without making changes live</li><li><strong>Publish / Update</strong> — makes the page live immediately</li></ul><hr><h2 id="container-column-toolbar" tabindex="-1">Container &amp; Column Toolbar <a class="header-anchor" href="#container-column-toolbar" aria-label="Permalink to &quot;Container &amp; Column Toolbar&quot;">​</a></h2><p>Hover over any container or column to reveal its toolbar:</p><table tabindex="0"><thead><tr><th>Button</th><th>Action</th></tr></thead><tbody><tr><td>⠿ (drag handle)</td><td>Drag to reorder</td></tr><tr><td>✏️</td><td>Open settings (background, padding, etc.)</td></tr><tr><td>⧉</td><td>Duplicate</td></tr><tr><td>📚</td><td>Save to Library</td></tr><tr><td>🌐</td><td>Save as Global Section</td></tr><tr><td>🗑️</td><td>Delete</td></tr></tbody></table><hr><h2 id="all-22-built-in-elements" tabindex="-1">All 22 Built-in Elements <a class="header-anchor" href="#all-22-built-in-elements" aria-label="Permalink to &quot;All 22 Built-in Elements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Category</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Heading</strong></td><td>Text</td><td>H1–H6 title with full typography control</td></tr><tr><td><strong>Title</strong></td><td>Text</td><td>Dynamic post/page title — auto-filled from content</td></tr><tr><td><strong>Text Block</strong></td><td>Text</td><td>Rich text paragraph (WYSIWYG editor)</td></tr><tr><td><strong>Text</strong></td><td>Text</td><td>Single-line text with dynamic source support</td></tr><tr><td><strong>Ticker</strong></td><td>Text</td><td>Horizontally scrolling announcement ticker</td></tr><tr><td><strong>Image</strong></td><td>Media</td><td>Single image — static or dynamic (Feature Image, Logo, Author Avatar)</td></tr><tr><td><strong>Gallery</strong></td><td>Media</td><td>Image grid, masonry, or slider with lightbox</td></tr><tr><td><strong>Video</strong></td><td>Media</td><td>YouTube, Vimeo, or self-hosted video</td></tr><tr><td><strong>Counter</strong></td><td>Interactive</td><td>Animated number that counts up on scroll</td></tr><tr><td><strong>Accordion</strong></td><td>Interactive</td><td>Collapsible FAQ / content sections</td></tr><tr><td><strong>Tabs</strong></td><td>Interactive</td><td>Tabbed content panels</td></tr><tr><td><strong>Button</strong></td><td>Layout</td><td>CTA button — solid, outline, or ghost style</td></tr><tr><td><strong>Card</strong></td><td>Layout</td><td>Image + title + description + button</td></tr><tr><td><strong>Spacer</strong></td><td>Layout</td><td>Vertical spacing — different per device</td></tr><tr><td><strong>Icon Box</strong></td><td>Layout</td><td>Icon + title + description, icon above or left</td></tr><tr><td><strong>Icon List</strong></td><td>Layout</td><td>Styled list with FontAwesome icons</td></tr><tr><td><strong>Post Grid</strong></td><td>Dynamic</td><td>Query and display posts in a responsive grid</td></tr><tr><td><strong>Post Content</strong></td><td>Dynamic</td><td>Renders the current post&#39;s full content body</td></tr><tr><td><strong>Post Meta</strong></td><td>Dynamic</td><td>Author, date, category, tags for the current post</td></tr><tr><td><strong>Star Rating</strong></td><td>Dynamic</td><td>Static star display (0–5 stars)</td></tr><tr><td><strong>Menu</strong></td><td>Navigation</td><td>Render a navigation menu — used in header builder</td></tr><tr><td><strong>HTML</strong></td><td>Advanced</td><td>Raw HTML / embed code block</td></tr></tbody></table><blockquote><p><strong>Custom elements</strong> can be registered via the hook API — see <a href="/falconcms/api/hooks.html">Hooks Reference</a>.</p></blockquote><hr><h2 id="responsive-preview" tabindex="-1">Responsive Preview <a class="header-anchor" href="#responsive-preview" aria-label="Permalink to &quot;Responsive Preview&quot;">​</a></h2><p>Use the device buttons in the top bar to preview your layout:</p><ul><li><strong>Desktop</strong> — full width</li><li><strong>Tablet</strong> — medium breakpoint</li><li><strong>Mobile</strong> — small breakpoint</li></ul><p>Each element, column, and container can be independently hidden per device. See <a href="/falconcms/builder/visibility.html">Device Visibility</a>.</p><hr><h2 id="saving-layouts-for-reuse" tabindex="-1">Saving Layouts for Reuse <a class="header-anchor" href="#saving-layouts-for-reuse" aria-label="Permalink to &quot;Saving Layouts for Reuse&quot;">​</a></h2><h3 id="library" tabindex="-1">Library <a class="header-anchor" href="#library" aria-label="Permalink to &quot;Library&quot;">​</a></h3><p>Save any container or column to the <strong>Library</strong> — reuse it on other pages as an independent copy.</p><h3 id="global-sections" tabindex="-1">Global Sections <a class="header-anchor" href="#global-sections" aria-label="Permalink to &quot;Global Sections&quot;">​</a></h3><p>Save a container as a <strong>Global Section</strong> — edit once, and it updates everywhere it&#39;s used across the site.</p><p>See <a href="/falconcms/builder/global-sections.html">Global Sections</a> and <a href="/falconcms/builder/library.html">Library</a> for details.</p>`,46)])])}const g=e(r,[["render",s]]);export{u as __pageData,g as default};
